class Node:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

def insert(root, char):
    if root is None:
        return Node(char)
    if char < root.val:
        root.left = insert(root.left, char)
    elif char > root.val:
        root.right = insert(root.right, char)
    return root

def process_recursive(seq, index, tree_root):
    if index >= len(seq):
        return tree_root
    char = seq[index].lower()
    tree_root = insert(tree_root, char)
    return process_recursive(seq, index + 1, tree_root)

